class FileProcessor {
    /**
     * Writes content to disk atomically by writing to a tmp file first,
     * then renaming to the target path. This avoids partial writes.
     */
    void writeAtomically(Path targetPath, String content) throws IOException {
        Path stagingPath = targetPath.resolveSibling(targetPath.getFileName() + ".staging");
        Files.writeString(stagingPath, content);
        Files.move(stagingPath, targetPath, StandardCopyOption.ATOMIC_MOVE);
    }
}
